const { SQSClient, ReceiveMessageCommand, DeleteMessageCommand } = require('@aws-sdk/client-sqs');
const { Client } = require('pg'); // PostgreSQL client
const dotenv = require('dotenv');

dotenv.config();

const sqsClient = new SQSClient({ region: process.env.AWS_REGION });
const dbClient = new Client({
    connectionString: process.env.DATABASE_URL,
});

const QUEUE_URL = process.env.SQS_QUEUE_URL;

async function processMessage(message) {
    const transactionData = JSON.parse(message.Body);

    // Validate transactionData here (e.g., check required fields, types)
    if (!transactionData.id || !transactionData.amount) {
        console.error('Invalid transaction data:', transactionData);
        return;
    }

    // Update database securely
    try {
        await dbClient.connect();
        const query = 'UPDATE transactions SET status = $1, updated_at = NOW() WHERE id = $2';
        const values = ['processed', transactionData.id];
        await dbClient.query(query, values);
    } catch (error) {
        console.error('Database update failed:', error);
    } finally {
        await dbClient.end();
    }
}

async function consumeMessages() {
    try {
        const data = await sqsClient.send(new ReceiveMessageCommand({
            QueueUrl: QUEUE_URL,
            MaxNumberOfMessages: 10,
            WaitTimeSeconds: 20,
        }));

        if (data.Messages) {
            for (const message of data.Messages) {
                await processMessage(message);

                // Delete message after processing
                await sqsClient.send(new DeleteMessageCommand({
                    QueueUrl: QUEUE_URL,
                    ReceiptHandle: message.ReceiptHandle,
                }));
            }
        }
    } catch (error) {
        console.error('Error receiving messages:', error);
    }
}

async function main() {
    while (true) {
        await consumeMessages();
    }
}

main();